    "bapUri": "{{bap_uri}}",
    "bppId": "{{bpp_id}}",
    "bppUri": "{{bpp_uri}}",
    "transactionId": "{{transaction_id}}",
    "messageId": "{{$guid}}",
    "networkId": "{{networkId}}",
    "timestamp": "{{$isoTimestamp}}",
    "try": false,
    "ttl": "PT30S",
    "schemaContext": [
      "https://schema.beckn.io/TripRequest/2.0/context.jsonld"
    ]
  },
  "message": {
    "intent": {
      "textSearch": "ride from Amsterdam Centrum (1012) to Museum Quarter (1071)",
      "filters": {
        "type": "jsonpath",
        "expression": "$[?(@.origin.address.addressLocality == 'Amsterdam' && @.origin.address.postalCode == '1012' && @.origin.address.addressCountry == 'NL' && @.destination.address.addressLocality == 'Amsterdam' && @.destination.address.postalCode == '1071')]"
      },
      "spatial": [
        {
          "op": "S_DWITHIN",
          "targets": "$['availableAt'][*]['geo']",
          "geometry": {
            "type": "Point",
            "coordinates": [
              4.9,
              52.38
            ]
          },
          "distanceMeters": 2000,
          "quantifier": "ANY",
          "srid": "EPSG:4326"
        }
      ]
    }
  }
}

